#### Cache TTL Testing Pattern
**File: `/Users/4thwithme/Documents/repo/recommendations-service/test/cache.module.e2e-spec.ts`**
```typescript
it('should respect TTL for cached items', async () => {
  const testKey = 'test-key';
  const testValue = { data: 'This will expire' };
  const shortTtl = 200;

  await cacheService.set({
    namespace: Namespaces.RELATED_ITEMS_MODEL,
    key: testKey,
    value: testValue,
    ttl: shortTtl,
  });

  const immediateResult = await cacheService.get<typeof testValue>({
    namespace: Namespaces.RELATED_ITEMS_MODEL,
    key: testKey,
  });
  expect(immediateResult).toEqual(testValue);

  await setTimeout(shortTtl + 100);

  const afterExpirationResult = await cacheService.get<typeof testValue>({
    namespace: Namespaces.RELATED_ITEMS_MODEL,
    key: testKey,
  });
  expect(afterExpirationResult).toBeNull();
}, 10000);
```

