    "test:e2e": "npm run db:reset:test && dotenv -e .env.test -- npx jest --runInBand --forceExit --config ./test/jest-e2e.config.ts",
    "test:unit:coverage": "dotenv -e .env.test -- npx jest --config ./test/jest-unit.coverage.config.ts",
    "test:e2e:coverage": "npm run db:reset:test && dotenv -e .env.test -- npx jest --runInBand --forceExit --config ./test/jest-e2e.coverage.config.ts",
    "test": "npm run code-quality-check && (npm run test:unit & npm run test:e2e & wait)",
    "db:reset:test": "dotenv -e .env.test -- ts-node -r tsconfig-paths/register ./scripts/reset-test-db.ts"
  }
}
```

Key points:
- `npm run test:e2e` runs `db:reset:test` first
- `--runInBand` executes tests sequentially (prevents parallel database conflicts)
- `--forceExit` ensures process exits after tests complete
- `dotenv -e .env.test` loads test environment variables

#### Database Reset Script
**File: `/Users/4thwithme/Documents/repo/recommendations-service/scripts/reset-test-db.ts`**

Complete lifecycle:
```typescript
async function resetTestDatabase() {
  // 1. Parse .env.test
  const connectionString = getEnv<string>({ key: DATABASE_URL, converter: String });

  // 2. Connect and drop all tables with foreign key check disabled
  const db = knex({
    client: 'mysql2',
    connection: {
      host: url.hostname,
      port: parseInt(url.port) || 3336,
      user: url.username,
      password: url.password,
      database: dbName,
    },
  });

  await db.raw('SET FOREIGN_KEY_CHECKS = 0');
  // Drop all tables
  for (const tableRow of tables) {
    const tableName = Object.values(tableRow)[0] as string;
    await db.raw(`DROP TABLE IF EXISTS \`${tableName}\``);
  }
  await db.raw('SET FOREIGN_KEY_CHECKS = 1');
  await db.destroy();

  // 3. Run migrations
  const migrationDb = knex({
    client: 'mysql2',
    connection: connectionString,
    migrations: {
      migrationSource: {
        getMigrations: async () => {
          const files = await fs.promises.readdir(
            path.join(__dirname, '../src/migrations'),
          );
          return files
            .filter((file: string) => file.endsWith('.ts'))
            .filter((file: string) => !excludedMigrations.includes(file))
            .sort();
        },
        // ...
      },
    },
  });

  await migrationDb.migrate.latest();
  await migrationDb.destroy();
}
```

